import{_ as e,o as i,c as s,a2 as t}from"./chunks/framework.DCVnL8g5.js";const k=JSON.parse('{"title":"Memoria, eviction y rendimiento","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/redis/11-memoria-eviction-y-rendimiento.md","filePath":"bases-de-datos/redis/11-memoria-eviction-y-rendimiento.md","lastUpdated":1782521464000}'),n={name:"bases-de-datos/redis/11-memoria-eviction-y-rendimiento.md"};function l(o,a,d,p,r,c){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="memoria-eviction-y-rendimiento" tabindex="-1">Memoria, eviction y rendimiento <a class="header-anchor" href="#memoria-eviction-y-rendimiento" aria-label="Permalink to &quot;Memoria, eviction y rendimiento&quot;">â€‹</a></h1><p>Redis vive en memoria. Por eso el diseno de claves, el tamano de los valores y la politica de eviction son decisiones centrales.</p><h2 id="ver-memoria" tabindex="-1">Ver memoria <a class="header-anchor" href="#ver-memoria" aria-label="Permalink to &quot;Ver memoria&quot;">â€‹</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">MEMORY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> STATS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">MEMORY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> USAGE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1</span></span></code></pre></div><p>Campos importantes:</p><ul><li><code>used_memory</code>: memoria usada por Redis.</li><li><code>used_memory_rss</code>: memoria vista por el sistema operativo.</li><li><code>mem_fragmentation_ratio</code>: relacion entre RSS y memoria usada.</li><li><code>maxmemory</code>: limite configurado.</li></ul><h2 id="configurar-limite" tabindex="-1">Configurar limite <a class="header-anchor" href="#configurar-limite" aria-label="Permalink to &quot;Configurar limite&quot;">â€‹</a></h2><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>maxmemory 2gb</span></span>
<span class="line"><span>maxmemory-policy allkeys-lru</span></span></code></pre></div><p>Sin limite, Redis puede consumir demasiada memoria y provocar problemas en el host.</p><h2 id="politicas-de-eviction" tabindex="-1">Politicas de eviction <a class="header-anchor" href="#politicas-de-eviction" aria-label="Permalink to &quot;Politicas de eviction&quot;">â€‹</a></h2><p>Cuando Redis alcanza <code>maxmemory</code>, aplica una politica.</p><table tabindex="0"><thead><tr><th>Politica</th><th>Comportamiento</th></tr></thead><tbody><tr><td><code>noeviction</code></td><td>Devuelve error en escrituras</td></tr><tr><td><code>allkeys-lru</code></td><td>Expulsa claves menos usadas</td></tr><tr><td><code>volatile-lru</code></td><td>Expulsa claves con TTL menos usadas</td></tr><tr><td><code>allkeys-lfu</code></td><td>Expulsa claves menos frecuentes</td></tr><tr><td><code>volatile-ttl</code></td><td>Expulsa claves con TTL mas cercano</td></tr><tr><td><code>allkeys-random</code></td><td>Expulsa claves aleatorias</td></tr></tbody></table><p>Para cache general, <code>allkeys-lru</code> o <code>allkeys-lfu</code> suelen ser razonables.</p><h2 id="ttl-y-cardinalidad" tabindex="-1">TTL y cardinalidad <a class="header-anchor" href="#ttl-y-cardinalidad" aria-label="Permalink to &quot;TTL y cardinalidad&quot;">â€‹</a></h2><p>El TTL evita acumulacion infinita:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:producto:10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{...}&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 300</span></span></code></pre></div><p>Evita claves sin expiracion para datos temporales.</p><h2 id="diseno-de-claves" tabindex="-1">Diseno de claves <a class="header-anchor" href="#diseno-de-claves" aria-label="Permalink to &quot;Diseno de claves&quot;">â€‹</a></h2><p>Usa nombres consistentes:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app:entidad:id</span></span>
<span class="line"><span>tienda:producto:10</span></span>
<span class="line"><span>tienda:sesion:abc</span></span>
<span class="line"><span>tienda:rate:user-1:2026-06-26T10:20</span></span></code></pre></div><p>No hagas claves gigantes ni metas demasiada semantica dificil de parsear.</p><h2 id="valores-grandes" tabindex="-1">Valores grandes <a class="header-anchor" href="#valores-grandes" aria-label="Permalink to &quot;Valores grandes&quot;">â€‹</a></h2><p>Redis puede guardar valores grandes, pero no siempre conviene.</p><p>Riesgos:</p><ul><li>Mas memoria.</li><li>Mas tiempo de red.</li><li>Bloqueos por serializacion.</li><li>Peor rendimiento en replicacion.</li></ul><p>Para documentos grandes, guarda solo lo necesario o usa una base principal externa.</p><h2 id="comandos-lentos" tabindex="-1">Comandos lentos <a class="header-anchor" href="#comandos-lentos" aria-label="Permalink to &quot;Comandos lentos&quot;">â€‹</a></h2><p>Ver slowlog:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SLOWLOG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GET</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SLOWLOG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LEN</span></span></code></pre></div><p>Configurar umbral:</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>slowlog-log-slower-than 10000</span></span></code></pre></div><p>El valor esta en microsegundos.</p><h2 id="pipeline" tabindex="-1">Pipeline <a class="header-anchor" href="#pipeline" aria-label="Permalink to &quot;Pipeline&quot;">â€‹</a></h2><p>Pipeline reduce round trips de red.</p><p>Ejemplo conceptual con <code>redis-cli</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pipe</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> comandos.txt</span></span></code></pre></div><p>En clientes de aplicacion, usa pipeline cuando tengas muchas operaciones independientes.</p><h2 id="mget-y-hmget" tabindex="-1">MGET y HMGET <a class="header-anchor" href="#mget-y-hmget" aria-label="Permalink to &quot;MGET y HMGET&quot;">â€‹</a></h2><p>Mejor agrupar lecturas relacionadas:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">MGET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> producto:1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> producto:2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> producto:3</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">HMGET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nombre</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rol</span></span></code></pre></div><h2 id="scan-en-vez-de-keys" tabindex="-1">SCAN en vez de KEYS <a class="header-anchor" href="#scan-en-vez-de-keys" aria-label="Permalink to &quot;SCAN en vez de KEYS&quot;">â€‹</a></h2><p>No uses:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">KEYS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> *</span></span></code></pre></div><p>Usa:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SCAN</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MATCH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tienda:producto:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> COUNT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span></span></code></pre></div><p><code>SCAN</code> itera incrementalmente y evita bloquear tanto.</p><h2 id="fragmentacion" tabindex="-1">Fragmentacion <a class="header-anchor" href="#fragmentacion" aria-label="Permalink to &quot;Fragmentacion&quot;">â€‹</a></h2><p>Una fragmentacion alta puede indicar que Redis reserva mas memoria del sistema de la que aparenta usar.</p><p>Revisa:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span></span></code></pre></div><p>En casos serios, evalua reinicio controlado, replica promotion o ajustes de allocator. No improvises en produccion.</p><h2 id="checklist-de-rendimiento" tabindex="-1">Checklist de rendimiento <a class="header-anchor" href="#checklist-de-rendimiento" aria-label="Permalink to &quot;Checklist de rendimiento&quot;">â€‹</a></h2><ul><li>Hay <code>maxmemory</code> definido?</li><li>La politica de eviction encaja con el uso?</li><li>Los datos temporales tienen TTL?</li><li>Hay comandos O(n) en rutas calientes?</li><li>Se usa pipeline donde hay muchas operaciones?</li><li><code>SLOWLOG</code> muestra comandos sospechosos?</li><li>El host esta evitando swap?</li></ul>`,53)])])}const m=e(n,[["render",l]]);export{k as __pageData,m as default};
